/* Node.js-style minimal event-sourcing flow (pseudo-code) */
// append an event with optimistic concurrency
await eventStore.appendToStream(`order-${orderId}`, [{ type: 'OrderPlaced', data }], { expectedVersion: 5 });

// read and rebuild state (with snapshot optimization idea)
const snapshot = await snapshotStore.get(`order-${orderId}`); // may be null
const events = await eventStore.readStream(`order-${orderId}`, { from: snapshot ? snapshot.version + 1 : 0 });
let state = snapshot ? snapshot.state : initialState;
for (const e of events) applyEvent(state, e);

// projection handler (idempotent)
async function handleEvent(e) {
  if (await projectionStore.hasProcessed(e.id)) return; // dedupe
  await updateReadModel(e);
  await projectionStore.markProcessed(e.id);
}
